import{_ as e,c as s,o as t,ag as n}from"./chunks/framework.BL0GrTA3.js";const u=JSON.parse('{"title":"Why VPP","description":"","frontmatter":{"title":"Why VPP","sidebar":false},"headers":[],"relativePath":"why-vpp.md","filePath":"why-vpp.md","lastUpdated":1780196654000}'),r={name:"why-vpp.md"};function o(i,a,p,l,c,h){return t(),s("div",null,[...a[0]||(a[0]=[n(`<div class="vpp-hero"><h1 class="vpp-hero-title">Why VPP</h1><p class="vpp-hero-lede"> VPP is for transcripts that must stay readable, auditable, and replayable as projects get longer, ideas get denser, and decisions become costly. </p><p class="vpp-hero-tagline"> A shared contract for how humans and assistants structure multi-turn work—on any model you already use. </p><div class="vpp-hero-actions"><a class="vpp-hero-button vpp-hero-button--brand" href="/#header-snippet"> Try VPP in your system prompt </a><a class="vpp-hero-button" href="/spec/"> Read the spec </a></div></div><div class="vpp-callout"><strong>VPP is not a chatbot in disguise.</strong> It does not swap models or pretend one system is another. VPP is a protocol layered on top of vanilla LLMs: a shared contract for how humans and assistants structure multi-turn work. </div><h2 id="what-breaks-in-normal-chat" tabindex="-1">What breaks in normal chat <a class="header-anchor" href="#what-breaks-in-normal-chat" aria-label="Permalink to &quot;What breaks in normal chat&quot;">​</a></h2><ul><li>Intent drifts: the “mode” of a turn (explore, draft, critique) stays implicit.</li><li>Corrections get lost: fixes are made, but the transcript stops being traceable.</li><li>Assumptions hide: choices accumulate without being named or counted.</li><li>Review becomes guesswork: collaborators can’t reliably replay reasoning.</li></ul><h2 id="what-vpp-adds" tabindex="-1">What VPP adds <a class="header-anchor" href="#what-vpp-adds" aria-label="Permalink to &quot;What VPP adds&quot;">​</a></h2><ul><li><strong>Explicit intent</strong> on every user turn via <code>!&lt;tag&gt;</code>.</li><li><strong>Mirrored intent</strong> on every assistant turn via <code>&lt;tag&gt;</code>.</li><li><strong>Auditability</strong> via a footer that records cycle, sources, and assumptions.</li><li><strong>Iterative control</strong> via a loop that makes correction and refinement legible.</li></ul><h2 id="where-vpp-shines" tabindex="-1">Where VPP shines <a class="header-anchor" href="#where-vpp-shines" aria-label="Permalink to &quot;Where VPP shines&quot;">​</a></h2><ul><li><strong>Long, big projects:</strong> the transcript stays navigable months later.</li><li><strong>Complex ideas:</strong> you can separate grounding, probing, drafting, and critique.</li><li><strong>Recursive prompting:</strong> when you don’t yet know what you want, the loop supports discovering it together—without losing structure.</li></ul><h2 id="a-micro-example" tabindex="-1">A micro-example <a class="header-anchor" href="#a-micro-example" aria-label="Permalink to &quot;A micro-example&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>!&lt;q&gt;</span></span>
<span class="line"><span>What are the unknowns in this plan?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;q&gt;</span></span>
<span class="line"><span>Unknowns:</span></span>
<span class="line"><span>- What “success” means (deliverable + audience).</span></span>
<span class="line"><span>- Which constraints are hard vs negotiable.</span></span>
<span class="line"><span>- What data we can cite vs must infer.</span></span>
<span class="line"><span>[Version=v1.4 | Tag=&lt;q_1&gt; | Sources=&lt;none&gt; | Assumptions=0 | Cycle=1/3 |</span></span>
<span class="line"><span>Locus=unknowns]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>!&lt;c&gt;</span></span>
<span class="line"><span>Clarify the deliverable and remove the weakest assumption.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;c&gt;</span></span>
<span class="line"><span>Understood. Deliverable: a single-page spec with a join-first CTA.</span></span>
<span class="line"><span>Removed assumption: that we can infer the user’s audience without</span></span>
<span class="line"><span>asking.</span></span>
<span class="line"><span>[Version=v1.4 | Tag=&lt;c_1&gt; | Sources=&lt;none&gt; | Assumptions=0 | Cycle=2/3 |</span></span>
<span class="line"><span>Locus=spec-tighten]</span></span></code></pre></div><p>The tag states intent. The footer makes progress reviewable.</p><h2 id="why-prompt-templates-aren-t-enough" tabindex="-1">Why prompt templates aren’t enough <a class="header-anchor" href="#why-prompt-templates-aren-t-enough" aria-label="Permalink to &quot;Why prompt templates aren’t enough&quot;">​</a></h2><p>Prompt templates are great at starting a session. They do not enforce structure across dozens of turns.</p><p>VPP makes structure continuous: Every turn declares intent, every response mirrors it, and the transcript stays auditable as it grows.</p><div class="vpp-try-box"><h3>Try VPP anywhere</h3><p> Paste the <a href="/#header-snippet">header snippet</a> into your system prompt, then begin with <code>!&lt;g&gt;</code> or <code>!&lt;q&gt;</code>. </p></div><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li>Read the normative spec: <a href="https://viableprompt.org/spec/" target="_blank" rel="noreferrer">Spec</a></li><li>Learn workflows and patterns: <a href="https://viableprompt.org/guide/" target="_blank" rel="noreferrer">Guide</a></li><li>Copy the system prompt once: <a href="/#header-snippet">Header snippet</a></li></ul><hr>`,18)])])}const g=e(r,[["render",o]]);export{u as __pageData,g as default};
